import chalk from 'chalk';

interface TaskOptions {
  title?: string;
  description?: string;
  priority?: string;
  id?: string;
}

export async function taskCommand(action: string | undefined, options: TaskOptions) {
  const validActions = ['list', 'start', 'complete', 'create'];

  if (!action || !validActions.includes(action)) {
    console.log(chalk.yellow('\nUsage: nexus task <action> [options]'));
    console.log(chalk.gray('\nActions:'));
    console.log('  list      - Show all tasks');
    console.log('  create    - Create a new task');
    console.log('  start     - Start a task (requires --id)');
    console.log('  complete  - Complete a task (requires --id)');
    console.log(chalk.gray('\nOptions:'));
    console.log('  -t, --title <title>        Task title');
    console.log('  -d, --description <desc>   Task description');
    console.log('  -p, --priority <level>     Priority: critical, high, medium, low');
    console.log('  -i, --id <id>              Task ID');
    console.log('');
    return;
  }

  console.log(chalk.cyan(`\n► Task command: ${action}`));

  if (action === 'create') {
    if (!options.title) {
      console.log(chalk.red('Error: --title is required for create'));
      return;
    }
    console.log(chalk.green(`Creating task: ${options.title}`));
    if (options.description) console.log(chalk.gray(`Description: ${options.description}`));
    if (options.priority) console.log(chalk.gray(`Priority: ${options.priority}`));
  } else if (action === 'list') {
    console.log(chalk.gray('\nQuerying task system...'));
    console.log(chalk.green('Use task_manager tool to view tasks\n'));
  } else if (action === 'start' || action === 'complete') {
    if (!options.id) {
      console.log(chalk.red(`Error: --id is required for ${action}`));
      return;
    }
    console.log(chalk.green(`${action === 'start' ? 'Starting' : 'Completing'} task: ${options.id}`));
  }
}
EOF
"}

